// src/Comments/CommentItem.js
import { useState } from "react";
import { timeAgo } from "../components/timeAgo";
import "../styles/events.css";

export default function CommentItem({
                                        comment,
                                        user,
                                        isAdmin,
                                        onDelete,
                                        toggleReaction,
                                        onReply,
                                    }) {
    const [showReplies, setShowReplies] = useState(false);

    const canDelete =
        user && (isAdmin || user.username === comment.username);

    const replies = comment.replies || [];
    const replyCount = replies.length;

    const reactions = comment.reactions || {};
    const counts = reactions.counts || {};
    const myReaction = reactions.myReaction || null;

    const username = comment.username || "unknown";

    return (
        <li className="yt-comment">
            {/* Avatar */}
            <div className="yt-avatar">
                {username[0].toUpperCase()}
            </div>

            {/* Main */}
            <div className="yt-main">
                {/* Header */}
                <div className="yt-header">
                    <span className="comment-username">@{username}</span>
                    <span className="yt-time">
                        · {timeAgo(comment.createdAt)}
                    </span>
                </div>

                {/* Body */}
                <div className="comment-content">
                    <div className="yt-text">
                        {comment.comment}
                    </div>
                </div>

                {/* Actions */}
                <div className="yt-actions">
                    {/* 👍 LIKE */}
                    <button
                        className={`yt-react ${myReaction === "LIKE" ? "active" : ""}`}
                        onClick={() => toggleReaction(comment, "LIKE")}
                    >
                        👍 {counts.LIKE || 0}
                    </button>

                    {/* ❤️ LOVE */}
                    <button
                        className={`yt-react ${myReaction === "LOVE" ? "active" : ""}`}
                        onClick={() => toggleReaction(comment, "LOVE")}
                    >
                        ❤️ {counts.LOVE || 0}
                    </button>

                    {/* 😂 LAUGH */}
                    <button
                        className={`yt-react ${myReaction === "LAUGH" ? "active" : ""}`}
                        onClick={() => toggleReaction(comment, "LAUGH")}
                    >
                        😂 {counts.LAUGH || 0}
                    </button>

                    {/* 🔥 FIRE */}
                    <button
                        className={`yt-react ${myReaction === "FIRE" ? "active" : ""}`}
                        onClick={() => toggleReaction(comment, "FIRE")}
                    >
                        🔥 {counts.FIRE || 0}
                    </button>

                    {/* Reply */}
                    {user && (
                        <button
                            className="yt-reply"
                            onClick={() => onReply(comment.id)}
                        >
                            Reply
                        </button>
                    )}

                    {/* Delete */}
                    {canDelete && (
                        <button
                            className="yt-delete"
                            onClick={() => onDelete(comment.id)}
                        >
                            Delete
                        </button>
                    )}
                </div>

                {/* Replies toggle */}
                {replyCount > 0 && (
                    <button
                        className="yt-toggle"
                        onClick={() => setShowReplies(v => !v)}
                    >
                        {showReplies
                            ? "Hide replies"
                            : `View ${replyCount} repl${replyCount > 1 ? "ies" : "y"}`}
                    </button>
                )}

                {/* Replies */}
                {showReplies && (
                    <ul className="yt-replies">
                        {replies.map(r => (
                            <CommentItem
                                key={r.id}
                                comment={r}
                                user={user}
                                isAdmin={isAdmin}
                                onDelete={onDelete}
                                toggleReaction={toggleReaction}
                                onReply={onReply}
                            />
                        ))}
                    </ul>
                )}
            </div>
        </li>
    );
}
